class Solution {
public:
    int countPairs(vector<int>& nums, int low, int high) {
        int res = 0;
        for (int x : nums) {
            res += countLessEqual(x, high) - countLessEqual(x, low - 1);
            insert(x);
        }
        return res;
    }

private:
    struct TrieNode {
        TrieNode* children[2] = {};
        int cnt = 0;
    };
    TrieNode* root = new TrieNode();
    static const int BITS = 15;

    void insert(int num) {
        TrieNode* node = root;
        for (int i = BITS; i >= 0; --i) {
            int bit = (num >> i) & 1;
            if (!node->children[bit]) node->children[bit] = new TrieNode();
            node = node->children[bit];
            ++node->cnt;
        }
    }

    int countLessEqual(int num, int limit) {
        TrieNode* node = root;
        int res = 0;
        for (int i = BITS; i >= 0 && node; --i) {
            int bitNum = (num >> i) & 1;
            int bitLimit = (limit >> i) & 1;
            if (bitLimit) {
                if (node->children[bitNum]) res += node->children[bitNum]->cnt;
                node = node->children[bitNum ^ 1];
            } else {
                node = node->children[bitNum];
            }
        }
        return res;
    }
};
```
efficiency: HIGH
time complexity: O(N log M) where M = 2^15
space complexity: O(N log M)
energy implications: MEDIUM
explanation: Uses a binary trie to count, for each element, how many previous elements XOR with it to a value ≤ high and ≤ low-1, then takes the difference. The trie stores counts per bit level, allowing O(log M) queries and insertions.

